@startuml
skinparam classAttributeIconSize 0

class "Pizza" <<A>> {
    + void prepare()
    + void bake()
    + void cut()
    + void box()
}

interface AbsFactory {
    Pizza createPizza();
}

abstract OrderPizza -|> AbsFactory : > creates via factory method < 

AbsFactory <|.. LDFactory 
LDFactory .. LDPepperPizza  
LDPepperPizza --|> Pizza  

AbsFactory <|.. BJFactory   
BJFactory ... BJCHeesePizza    
BjCheesepizza ---+-> PIZZA    

' Note: The dashed lines from factories to specific pizzas are represented by dependencies or associations depending on context; here we use dependency for clarity in creation process.


@enduml
